{
  "features": [
    {
      "title": "Metadata file serving",
      "description": "Allows serving of distribution metadata files independently.",
      "introduced_version_claim": "null",
      "spec_claims": [
        {
          "claim_text": "Each anchor tag pointing to a distribution MAY have a data-dist-info-metadata attribute.",
          "claim_type": "structural",
          "testable": true,
          "pep_section_ref": "PEP-658#specification"
        },
        {
          "claim_text": "The presence of the data-dist-info-metadata attribute indicates the distribution MUST contain a Core Metadata file that will not be modified when the distribution is processed and/or installed.",
          "claim_type": "structural",
          "testable": true,
          "pep_section_ref": "PEP-658#specification"
        },
        {
          "claim_text": "If a data-dist-info-metadata attribute is present, the repository MUST serve the distribution's Core Metadata file alongside the distribution with a.metadata appended to the distribution's file name.",
          "claim_type": "structural",
          "testable": true,
          "pep_section_ref": "PEP-658#specification"
        },
        {
          "claim_text": "The repository SHOULD provide the hash of the Core Metadata file as the data-dist-info-metadata attribute's value using the syntax <hashname>=<hashvalue>.",
          "claim_type": "structural",
          "testable": true,
          "pep_section_ref": "PEP-658#specification"
        },
        {
          "claim_text": "The repository MAY use true as the attribute's value if a hash is unavailable.",
          "claim_type": "structural",
          "testable": true,
          "pep_section_ref": "PEP-658#specification"
        }
      ]
    },
    {
      "title": "Backwards compatibility",
      "description": "Ensures backwards compatibility with older tools and existing behaviors.",
      "introduced_version_claim": "null",
      "spec_claims": [
        {
          "claim_text": "If an anchor tag lacks the data-dist-info-metadata attribute, tools are expected to revert to their current behaviour of downloading the distribution to inspect the metadata.",
          "claim_type": "behavioural",
          "testable": true,
          "pep_section_ref": "PEP-658#backwards-compatibility"
        },
        {
          "claim_text": "Older tools not supporting the new data-dist-info-metadata attribute are expected to ignore the attribute and maintain their current behaviour of downloading the distribution to inspect the metadata.",
          "claim_type": "behavioural",
          "testable": true,
          "pep_section_ref": "PEP-658#backwards-compatibility"
        }
      ]
    }
  ]
}
